// ────────────────────────────────────────────────────────────────────────────
// VERIFY SIGNATURE — rejette les requêtes sans le header X-Pessobot-Signature
// attendu. À désactiver en dev si VITE_PESSOBOT_SIGNATURE est vide côté front.
// ⚠️ n8n Cloud (Starter/Pro) n'expose pas $env → le secret est hardcodé ci-dessous.
// ────────────────────────────────────────────────────────────────────────────
const expected = '607dd413213a97fe2a54f9ebdab7341596d603640bb093ae';
const webhook = $('Webhook PessoBot').first().json;
const received = (webhook.headers && (webhook.headers['x-pessobot-signature'] || webhook.headers['X-Pessobot-Signature'])) || '';

if (expected && received !== expected) {
  throw new Error('Unauthorized: invalid or missing X-Pessobot-Signature header');
}

return [{ json: webhook }];

// ────────────────────────────────────────────────────────────────────────────
// BUILD SYSTEM PROMPT (v2.1 — RPC snapshot + Óra+ pitch conditionnel)
// Sources Supabase :
//   • public.fn_pessobot_profile_snapshot(uuid) → profil enrichi
//   • public.v_pessobot_menu                    → carte à jour
//   • public.bar_settings                       → adresse / horaires / contact / Óra+
// ────────────────────────────────────────────────────────────────────────────

// 1. Webhook — message utilisateur
const webhook = $('Webhook PessoBot').first().json;
const userMsg = (webhook.body && webhook.body.message) || '';
const sessionId = (webhook.body && webhook.body.sessionid) || 'session-inconnue';
const userId = (webhook.body && webhook.body.userId) || null;

// 2. Snapshot profil (RPC) — 0 ou 1 ligne
let snap = {};
try {
  const rows = $('Get Profile Snapshot (RPC)').all();
  if (rows[0] && rows[0].json) snap = rows[0].json;
} catch (e) { /* visiteur ou RPC indispo */ }

const isConnected = !!userId && !!snap.first_name;
const firstName = snap.first_name || 'Membre';
const plan = (snap.plan || 'free').toLowerCase();
const isOraPlus = ['ora_plus', 'starter', 'premium', 'vip'].includes(plan);
const totalOrders = snap.total_orders || 0;
const isNewcomer = isConnected && totalOrders === 0;
const isRegular = isConnected && totalOrders >= 3;

let clientStatus = 'VISITOR';
if (isConnected) clientStatus = isOraPlus ? 'VIP_MEMBER' : 'FREE_MEMBER';

// 3. Signaux perso (favoris, prochain event, prochain bilan)
const favorite = snap.favorite_product || null;
const upcomingEvent = snap.upcoming_event || null;
const upcomingBilan = snap.upcoming_bilan || null;

const personalSignals = [];
if (favorite && favorite.name) {
  personalSignals.push(`• Produit préféré : ${favorite.name} (${favorite.orders_count}x commandé).`);
}
if (upcomingEvent && upcomingEvent.title) {
  personalSignals.push(`• Prochain événement inscrit : "${upcomingEvent.title}" le ${upcomingEvent.date}${upcomingEvent.heure ? ' à ' + upcomingEvent.heure : ''}.`);
}
if (upcomingBilan && upcomingBilan.date_rdv) {
  personalSignals.push(`• Prochain bilan bien-être : ${upcomingBilan.date_rdv}${upcomingBilan.heure_rdv ? ' à ' + upcomingBilan.heure_rdv : ''} (statut : ${upcomingBilan.statut}).`);
}
if (isNewcomer) personalSignals.push(`• ${firstName} n'a jamais commandé — on accueille chaleureusement.`);
if (isRegular) personalSignals.push(`• ${firstName} est un habitué (${totalOrders} commandes) — ton familier, pas d'upsell basique.`);

const personalBlock = personalSignals.length
  ? `\nSIGNAUX PERSO (à utiliser avec tact, ne jamais lister brut) :\n${personalSignals.join('\n')}`
  : '';

// 4. Menu dynamique (v_pessobot_menu)
const menuRows = $('Get Menu').all().map((r) => r.json || {});
const categoryLabel = {
  wellness: '🍵 WELLNESS',
  energie:  '⚡ ÉNERGIE',
  shakes:   '🥤 SHAKES',
  coffee:   '☕ COFFEE',
};
const menuByCategory = menuRows.reduce((acc, row) => {
  const cat = (row.category || 'divers').toLowerCase();
  (acc[cat] = acc[cat] || []).push(row);
  return acc;
}, {});
const formatRow = (r) => {
  const bits = [];
  if (r.price != null) bits.push(`${Number(r.price).toFixed(0)}€`);
  if (r.protein != null) bits.push(`${r.protein}g prot`);
  if (r.calories != null) bits.push(`${r.calories}kcal`);
  const meta = bits.length ? ` (${bits.join(' · ')})` : '';
  const ings = Array.isArray(r.ingredients) && r.ingredients.length ? ` — ${r.ingredients.join(', ')}` : '';
  const ben  = Array.isArray(r.benefits)    && r.benefits.length    ? ` [${r.benefits.join(', ')}]`    : '';
  return `• ${r.name}${meta}${ings}${ben}`;
};
let menuBlock = '';
for (const cat of Object.keys(categoryLabel)) {
  if (menuByCategory[cat] && menuByCategory[cat].length) {
    menuBlock += `\n\n${categoryLabel[cat]}\n` + menuByCategory[cat].map(formatRow).join('\n');
  }
}
if (!menuBlock) menuBlock = '\n(Menu temporairement indisponible — excuse-toi et propose de rappeler plus tard.)';

// 5. Infos bar (bar_settings)
let bar = { address: {}, hours: [], contact: {}, subscription_info: {} };
try {
  const rows = $('Get Bar Settings').all();
  if (rows[0] && rows[0].json) bar = rows[0].json;
} catch (e) { /* fallback vide */ }

const addressLine = (bar.address && bar.address.full) || '';
const hoursLines = Array.isArray(bar.hours)
  ? bar.hours.map((h) => `• ${h.label} : ${h.value}`).join('\n')
  : '';
const contact = bar.contact || {};
const contactLines = [
  contact.email     ? `• Email : ${contact.email}` : '',
  contact.phone     ? `• Téléphone : ${contact.phone}` : '',
  contact.instagram ? `• Instagram : ${contact.instagram}` : '',
].filter(Boolean).join('\n');

const infosBar = `\n📍 ADRESSE : ${addressLine || '(non renseignée — dis-le poliment sans inventer.)'}\n\n🕐 HORAIRES :\n${hoursLines || '(non renseignés — réponds « je n\u2019ai pas cette info à jour, je te recontacte »)'}\n\n📧 CONTACT :\n${contactLines || '(non renseigné)'}`;

// 6. Óra+ (pitch conditionnel depuis bar_settings.subscription_info)
const oraPlus = (bar.subscription_info && bar.subscription_info.ora_plus) || null;
let oraPlusBlock = '';
if (oraPlus && Array.isArray(oraPlus.benefits) && oraPlus.benefits.length) {
  const benefits = oraPlus.benefits.map((b) => `• ${b}`).join('\n');
  oraPlusBlock = `\n\nABONNEMENT ${oraPlus.name || 'Óra+'} (source Supabase — à citer tel quel, jamais inventer) :\n${oraPlus.tagline || ''}\nPrix : ${oraPlus.price || ''} ${oraPlus.period || ''} — ${oraPlus.highlight || ''}\nAvantages :\n${benefits}${oraPlus.cta_url ? `\nPour s'inscrire, partage ce lien markdown : [S'abonner à ${oraPlus.name || 'Óra+'}](${oraPlus.cta_url})` : ''}`;
}

// 7. Closing tactique (contextualisé par le statut + snapshot)
let closing = '';
if (clientStatus === 'VISITOR') {
  closing = `🔴 VISITEUR : après le conseil, ferme par : « Crée ton compte gratuit pour commander ». Ne demande jamais de paiement.`;
} else if (clientStatus === 'FREE_MEMBER') {
  if (totalOrders >= 3 && oraPlus) {
    closing = `🟠 MEMBRE FIDÈLE FREE : ${firstName} a commandé ${totalOrders} fois. Si une occasion naturelle se présente (prix, fréquence), glisse le pitch Óra+ UNE fois, concret, en citant 1 ou 2 avantages réels (voir bloc ABONNEMENT ci-dessous). Ne force jamais.`;
  } else if (oraPlus) {
    closing = `🟠 MEMBRE FREE : si le produit est éligible Óra+, glisse : « Avec ${oraPlus.name || 'Óra+'} ce serait moins cher (${oraPlus.highlight || ''}) ». Une seule fois, sans insister.`;
  } else {
    closing = `🟠 MEMBRE FREE : conseille simplement, pas d'upsell (Óra+ non configuré).`;
  }
} else {
  closing = `🟢 ${oraPlus ? oraPlus.name : 'VIP'} : ${firstName} est déjà abonné. Confirme simplement le plaisir, rappelle ponctuellement les avantages exclusifs (bilan prioritaire, places événements), pas d'upsell.`;
}

// 8. Persona PessoBot (~900 tokens)
const who = isConnected ? firstName : 'un visiteur anonyme';
const systemPrompt = `Tu es PessoBot, le coach nutrition du bar PessÓra.

⚠️ RÈGLES ABSOLUES :
1. Tu ne donnes JAMAIS d'infos bar/menu/abonnement qui ne sont pas dans les blocs ci-dessous.
2. Si l'info n'est pas disponible, dis-le simplement (« je n'ai pas cette info à jour »).
3. Tu justifies toujours un conseil par une donnée technique (ingrédient, gramme de protéine, kcal).
4. Tu parles à ${who} (statut : ${clientStatus}${isConnected ? `, plan : ${plan}` : ''}).
5. Tu restes court, chaleureux, précis. Pas de markdown lourd (pas de titres, pas de tableaux).
6. Tu utilises les signaux perso avec tact — jamais récité brut.
7. Pour partager un lien, utilise TOUJOURS le format markdown [libellé](URL). Exemples : [voir le menu](https://pessora.mq/menu), [nos événements](https://pessora.mq/evenements), [créer un compte](https://pessora.mq/inscription). Les liens sont rendus cliquables côté front et ouverts en nouvel onglet — ne donne jamais une URL brute dans une phrase (sauf en fin de ligne dédiée).

MÉTHODE CONSULTANT :
- Si la demande est vague ("je veux de l'énergie"), pose UNE question de ciblage.
- Si la demande est précise ("j'ai faim", "sèche", "mal aux articulations"), donne LA solution + pourquoi.

CLOSING :
${closing}
${personalBlock}

INFOS BAR (source Supabase — à citer telles quelles) :
${infosBar}

CARTE À JOUR (source Supabase — à citer telle quelle) :${menuBlock}${oraPlusBlock}
`;

return [{ json: { systemPrompt, userMessage: userMsg, sessionId } }];

let rawText = $input.first().json.output || '';
let cleanText = rawText
  .replace(/^[#]+\s+/gm, '')
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\*(.*?)\*/g, '$1')
  .replace(/^[-\u2022]\s+/gm, '👉 ')
  .replace(/^\s*-{3,}\s*$/gm, '')
  .trim();
return [{ json: { response: cleanText } }];
